import { Component, OnInit, inject, ChangeDetectorRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-cv-builder',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './cv-builder.component.html',
  styleUrls: ['./cv-builder.component.css']
})
export class CvBuilderComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  cvData = { title: '', skills: '', experience: '', education: '' };
  candidateName: string = '';
  successMessage: string = '';
  isSaving: boolean = false;

  ngOnInit() {
    this.candidateName = localStorage.getItem('name') || 'Mon Profil';
    this.fetchCurrentCV();
  }

  // 📥 CHARGEMENT AUTOMATIQUE DU CV EXISTANT EN BD
  fetchCurrentCV() {
    const targetUrl = 'http://localhost:3000/api/candidate/cv/details'; // On créera cette route de lecture juste après
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'GET',
      headers: { 'Authorization': token ? `Bearer ${token}` : '' }
    })
    .then(res => res.ok ? res.json() : null)
    .then(data => {
      if (data) {
        this.cvData.title = data.title || '';
        this.cvData.skills = data.skills || '';
        this.cvData.experience = data.experience || '';
        this.cvData.education = data.education || '';
        this.cdr.detectChanges();
      }
    })
    .catch(err => console.warn("Aucun CV existant trouvé, mode création actif."));
  }

  // Découpe la chaîne de caractères par les virgules pour faire les badges à droite
  getSkillsArray(): string[] {
    if (!this.cvData.skills) return [];
    return this.cvData.skills.split(',').filter(s => s.trim() !== '');
  }

  // 📤 ENREGISTREMENT OU MISE À JOUR DANS MYSQL
  onSaveCV(event: Event) {
    event.preventDefault();
    this.isSaving = true;

    const targetUrl = 'http://localhost:3000/api/candidate/cv/save'; // Route fournie dans votre candidate.routes.js
    const token = localStorage.getItem('token');

    fetch(targetUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : ''
      },
      body: JSON.stringify(this.cvData)
    })
    .then(async res => {
      if (!res.ok) throw new Error("Erreur de sauvegarde.");
      return res.json();
    })
    .then(() => {
      this.successMessage = "Votre CV en ligne a été enregistré et synchronisé avec succès !";
      this.isSaving = false;
      this.cdr.detectChanges();
      setTimeout(() => { this.successMessage = ''; this.cdr.detectChanges(); }, 3500);
    })
    .catch(err => {
      alert("Impossible de sauvegarder votre CV pour le moment.");
      this.isSaving = false;
      this.cdr.detectChanges();
    });
  }
}
 
<div class="cv-container-compact">
  
  <div class="card-header-flex-compact">
    <div class="card-header-left">
      <h3><i class="bi bi-file-earmark-person-fill" style="color: #0ea5e9;"></i> Générateur de CV Professionnel</h3>
      <p style="margin: 2px 0 0 0; color: #64748b; font-size: 13px;">Remplissez vos informations pour concevoir votre CV en ligne TunJob.</p>
    </div>
  </div>

  <!-- Alerte temporisée de succès -->
  @if (successMessage) {
    <div class="alert-box-compact alert-success">{{ successMessage }}</div>
  }

  <!-- 📊 DISPOSITION DOUBLE PANNEAU SANS SCROLL -->
  <div class="cv-split-layout">
    
    <!-- ================= PANNEAU GAUCHE : FORMULAIRE DE SAISIE ================= -->
    <div class="cv-panel-card">
      <div class="panel-inner-title"><i class="bi bi-pencil-square"></i> Vos informations</div>
      
      <form (ngSubmit)="onSaveCV($event)" class="compact-form-grid-vertical">
        
        <div class="form-group-compact">
          <label for="cv_title">Titre du profil pro *</label>
          <input type="text" id="cv_title" name="cv_title" [(ngModel)]="cvData.title" placeholder="Ex: Développeur Fullstack Angular / Node" required>
        </div>

        <div class="form-group-compact">
          <label for="skills">Compétences clés (Séparées par des virgules) *</label>
          <input type="text" id="skills" name="skills" [(ngModel)]="cvData.skills" placeholder="Ex: Angular, TypeScript, SQL, Git" required>
        </div>

        <div class="form-group-compact">
          <label for="experience">Expériences professionnelles majeures *</label>
          <textarea id="experience" name="experience" [(ngModel)]="cvData.experience" rows="4" placeholder="Ex: Développeur Web chez TechTunisia (2 ans) - Création d'applications complexes..." required></textarea>
        </div>

        <div class="form-group-compact">
          <label for="education">Formations & Diplômes *</label>
          <textarea id="education" name="education" [(ngModel)]="cvData.education" rows="3" placeholder="Ex: Licence en Informatique - ISG Tunis (2024)" required></textarea>
        </div>

        <div class="form-actions-compact">
          <button type="submit" class="btn-save-cv-compact" [disabled]="isSaving">
            <i class="bi bi-cloud-arrow-up-fill"></i> Enregistrer mon CV
          </button>
        </div>
      </form>
    </div>

    <!-- ================= PANNEAU DROIT : APERÇU EN TEMPS RÉEL (LIVE PREVIEW) ================= -->
    <div class="cv-panel-card preview-bg">
      <div class="panel-inner-title"><i class="bi bi-eye-fill"></i> Aperçu en temps réel</div>
      
      <!-- Feuille de style type CV papier -->
      <div class="cv-paper-preview">
        
        <!-- En-tête du CV -->
        <div class="cv-header-preview">
          <h4>{{ candidateName || 'Votre Nom & Prénom' }}</h4>
          <span class="cv-preview-subtitle">{{ cvData.title || 'Intitulé de votre métier recherché' }}</span>
        </div>

        <!-- Corps du CV -->
        <div class="cv-body-preview">
          
          <!-- Bloc Compétences -->
          <div class="cv-section-preview">
            <h5><i class="bi bi-star-fill"></i> Compétences</h5>
            <div class="cv-tags-container">
              @if (cvData.skills) {
                @for (skill of getSkillsArray(); track skill) {
                  <span class="skill-tag-preview">{{ skill.trim() }}</span>
                }
              } @else {
                <span style="color: #94a3b8; font-style: italic; font-size: 12px;">Aucune compétence saisie.</span>
              }
            </div>
          </div>

          <!-- Bloc Expériences -->
          <div class="cv-section-preview">
            <h5><i class="bi bi-briefcase-fill"></i> Parcours Professionnel</h5>
            <p class="cv-text-preview-block">{{ cvData.experience || 'Détaillez vos anciens postes, stages ou projets ici...' }}</p>
          </div>

          <!-- Bloc Formations -->
          <div class="cv-section-preview">
            <h5><i class="bi bi-mortarboard-fill"></i> Éducation & Études</h5>
            <p class="cv-text-preview-block">{{ cvData.education || 'Renseignez vos diplômes, certifications ou universités...' }}</p>
          </div>

        </div>

      </div>
    </div>

  </div>
</div>
